54	njs_array_alloc(njs_vm_t *vm, njs_bool_t flat, uint64_t length, uint32_t spare)
55	{
56	    uint64_t     size;
57	    njs_int_t    ret;
58	    njs_array_t  *array;
59	    njs_value_t  value;
60	
61	    if (njs_slow_path(length > UINT32_MAX)) {
62	        goto overflow;
63	    }
64	
65	    array = njs_mp_alloc(vm->mem_pool, sizeof(njs_array_t));
66	    if (njs_slow_path(array == NULL)) {
67	        goto memory_error;
68	    }
69	
70	    size = length + spare;
71	
72	    if (flat || size <= NJS_ARRAY_LARGE_OBJECT_LENGTH) {
73	        array->data = njs_mp_align(vm->mem_pool, sizeof(njs_value_t),
74	                                   size * sizeof(njs_value_t));
75	        if (njs_slow_path(array->data == NULL)) {
76	            goto memory_error;
77	        }
78	
79	    } else {
80	        array->data = NULL;
81	    }
82	
83	    array->start = array->data;
84	    njs_flathsh_init(&array->object.hash);
85	    array->object.shared_hash = vm->shared->array_instance_hash;
86	    array->object.__proto__ = njs_vm_proto(vm, NJS_OBJ_TYPE_ARRAY);
87	    array->object.slots = NULL;
88	    array->object.type = NJS_ARRAY;
89	    array->object.shared = 0;
90	    array->object.extensible = 1;
91	    array->object.error_data = 0;
92	    array->object.fast_array = (array->data != NULL);
93	
94	    if (njs_fast_path(array->object.fast_array)) {
95	        array->size = size;
96	        array->length = length;
97	
98	    } else {
99	        array->size = 0;
100	        array->length = 0;
101	
102	        njs_set_array(&value, array);
103	        ret = njs_array_length_redefine(vm, &value, length, 1);
104	        if (njs_slow_path(ret != NJS_OK)) {
105	            return NULL;
106	        }
107	    }
108	
109	    return array;
110	
111	memory_error:
112	
113	    njs_memory_error(vm);
114	
115	    return NULL;
116	
117	overflow:
118	
119	    njs_range_error(vm, "Invalid array length");
120	
121	    return NULL;
122	}
123	
124	
125	void
126	njs_array_destroy(njs_vm_t *vm, njs_array_t *array)
127	{
128	    if (array->data != NULL) {
129	        njs_mp_free(vm->mem_pool, array->data);
130	    }
131	
132	    /* TODO: destroy keys. */
133	
134	    njs_mp_free(vm->mem_pool, array);
135	}
136	
137	
138	njs_int_t
139	njs_array_convert_to_slow_array(njs_vm_t *vm, njs_array_t *array)
140	{
141	    uint32_t           i, length;
142	    njs_value_t        value;
143	    njs_object_prop_t  *prop;
144	
145	    if (njs_slow_path(!array->object.fast_array)) {
146	        return NJS_OK;
147	    }
148	
149	    njs_set_array(&value, array);
150	    array->object.fast_array = 0;
151	
152	    length = array->length;
153	
154	    for (i = 0; i < length; i++) {
155	        if (njs_is_valid(&array->start[i])) {
156	            prop = njs_object_property_add(vm, &value, njs_number_atom(i), 0);
157	            if (njs_slow_path(prop == NULL)) {
158	                return NJS_ERROR;
159	            }
160	
161	            njs_value_assign(njs_prop_value(prop), &array->start[i]);
162	        }
163	    }
164	
165	    njs_mp_free(vm->mem_pool, array->data);
166	    array->start = NULL;
167	
168	    return NJS_OK;
169	}
170	
171	
172	njs_int_t
