static njs_int_t
njs_number_to_string_radix(njs_vm_t *vm, njs_value_t *string,
    double number, uint32_t radix)
{
    int            len;
    size_t         size;
    u_char         buf[NJS_NUMBER_RADIX_BUF_SIZE];
    njs_int_t      ret;
