    len = njs_dtoa_max_len(number, (int) radix, 0,
                           JS_DTOA_FORMAT_FREE | JS_DTOA_EXP_DISABLED);
    if (njs_slow_path((size_t) len + 1 > NJS_NUMBER_RADIX_BUF_SIZE)) {
        njs_internal_error(vm, "radix buffer overflow");
